func TestNovelReportsQuarterSummarizesPeriod(t *testing.T) {
	cases := []struct {
		name                   string
		wantContributionAmount float64
	}{
		{name: "filings and contributions share period summary", wantContributionAmount: 25},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			dbPath := newLDANovelTestDB(t)
			seedLDANovelRecord(t, dbPath, "filings", "f1", `{"id":1,"filing_uuid":"f1","filing_year":2024,"filing_period":"mid_year","filing_period_display":"Mid-Year","filing_type":"MA","filing_type_display":"Mid-Year Amendment","income":"1000.00","expenses":"100.00","client":{"name":"Boeing Company"},"registrant":{"name":"Akin Gump"},"lobbying_activities":[{"general_issue_code_display":"Defense","government_entities":[{"name":"Department of Defense"}]}]}`)
			seedLDANovelRecord(t, dbPath, "contributions", "c1", `{"id":2,"filing_uuid":"c1","filing_year":2024,"filing_period":"mid_year","filing_period_display":"Mid-Year","contribution_items":[{"amount":"25.00"}]}`)
			flags := &rootFlags{asJSON: true}
			rows := runLDANovelRows(t, newNovelReportsQuarterCmd(flags), "--db", dbPath, "--year", "2024", "--period", "mid_year")
			if len(rows) != 1 {
				t.Fatalf("rows = %#v, want one period row", rows)
			}
			if rows[0]["filings"].(float64) != 1 || rows[0]["amendments"].(float64) != 1 {
				t.Fatalf("row = %#v, want one filing amendment", rows[0])
			}
			if rows[0]["contribution_amount"].(float64) != tc.wantContributionAmount {
				t.Fatalf("row = %#v, want contribution_amount %v", rows[0], tc.wantContributionAmount)
			}
			if rows[0]["top_issue"] != "Defense (1)" {
				t.Fatalf("top_issue = %v, want Defense (1)", rows[0]["top_issue"])
			}
		})
	}
}

func TestNovelReportsQuarterHintsWhenContributionsUnsynced(t *testing.T) {
	dbPath := newLDANovelTestDB(t)
	seedLDANovelRecord(t, dbPath, "filings", "f1", `{"id":1,"filing_uuid":"f1","filing_year":2024,"filing_period":"mid_year","filing_type":"MM"}`)
	seedLDANovelSyncState(t, dbPath, "filings")

	flags := &rootFlags{asJSON: true}
	rows, stderr := runLDANovelRowsWithStderr(t, newNovelReportsQuarterCmd(flags), "--db", dbPath, "--year", "2024", "--period", "mid_year")
	if len(rows) != 1 {
		t.Fatalf("rows = %#v, want filing summary even without contributions", rows)
	}
	if rows[0]["contribution_items"].(float64) != 0 {
		t.Fatalf("row = %#v, want zero contribution items", rows[0])
	}
	if !strings.Contains(stderr, "sync --resources contributions") {
		t.Fatalf("stderr = %q, want targeted contributions sync hint", stderr)
	}
}
